import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"五毒","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/五毒.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/五毒.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/武学基础/五毒.md"};function d(p,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"五毒",tabindex:"-1"},[n("五毒 "),r("a",{class:"header-anchor",href:"#五毒","aria-label":'Permalink to "五毒"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),s('<h1 id="五毒-1" tabindex="-1">五毒 <a class="header-anchor" href="#五毒-1" aria-label="Permalink to &quot;五毒&quot;">​</a></h1><p>技艺<br> 需要关键属性含有生理属性的能量池<br> 五毒-壁虎功<br> D+500<br> 出自《五毒》，四师兄所学之功法，壁虎功身轻矫健，随处皆可攀援，<br> 习得者可在垂直平面上进行移动，但回合结束时没有落脚点会正常坠落。<br> 同时壁虎功攀墙伏壁时可以借劲力反弹，以增加本身的劲力。<br> 在垂直平面上时以一个自由动作发动，你借力增强自己的力量，你免疫坠落伤害持续1轮，额外消耗2点能量获得，你的力量属性临时+2，临时属性不能超过当前等级上限。</p><p>技艺<br> 需要关键属性含有生理属性的能量池<br> 五毒-蜈蚣功<br> D+500<br> 出自《五毒》，大师兄所学之功法，习得蜈蚣功后出招犹如百足千手，出招极为迅速，你以拳，腿等部位发动的肉搏攻击具有高速5<br> 以一个自由动作发动，你消耗2点能量，再次强化你的出招速度，你以拳，腿等部位发动的肉搏攻击具有【连射】，如果你不具有天生武器伤害，则你临时具有3l天生武器伤害，持续1轮。</p><p>技艺<br> 需要关键属性含有生理属性的能量池<br> 五毒-蛤蟆功<br> D+500<br> 出自《五毒》，五师兄所学之功法，习得蛤蟆功后，可以刀枪不入。<br> 你获得基于格挡防御的近战伤害吸收2点<br> 以一个自由动作发动，你消耗2点能量，运足自身真气，使全身肌肤如铁，具有断木折铁之功，你获得2点格挡防御，持续1轮。</p><p>技艺<br> 需要关键属性含有生理属性的能量池<br> 五毒-蝎子功<br> D+500<br> 出自《五毒》，三师兄所学之功法，手如蝎钳腿似钩，<br> 无需通过检定也可进行攀爬移动，以腿发起的肉搏攻击具有【贯穿】<br> 以一个自由动作发动，你消耗2点能量进行准备，在进行肉搏攻击时将自己的蝎钩腿攻向另一个敌人，你的下次攻击额外在你的肉搏攻击范围内新增一个其他攻击目标，攻击具有破甲1，持续1轮。</p><p>技艺<br> 需要关键属性含有生理属性的能量池<br> 五毒-灵蛇功<br> D+500<br> 出自《五毒》，二师兄所学之功法，右为蛇头，左为蛇尾，长于游走，胜在灵。<br> 伏地时可全速移动，取消潜行行走速度限制<br> 以一个自由动作发动，你消耗2点能量，你的肉搏攻击改为造成穿刺伤害，并且这次攻击中，你的天生武器伤害提升2点，持续1轮。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
